export function defineCommandCatalog(catalog) {
    return {
        defineCommands(defs) {
            const out = {};
            for (const [flowCommandId, def] of Object.entries(defs)) {
                const catalogId = def.command ?? flowCommandId;
                const entry = catalog[catalogId];
                if (entry === undefined) {
                    throw new Error(`Flow command "${flowCommandId}" references unknown command "${catalogId}"`);
                }
                out[flowCommandId] = {
                    file: entry.file,
                    description: def.description,
                    ...(def.args === undefined ? {} : { args: def.args }),
                };
            }
            return out;
        },
    };
}
